update sam_achievement
set review_result = #{reviewStatus},
    reviewed_at = case
        when #{reviewStatus} = 0 then null
        else now()
    end,
    review_reason = case
        when #{reviewStatus} = 1 then #{rejectReason}
        else null
    end,
    audit_by = case
        when #{reviewStatus} = 0 then null
        else #{auditBy}
    end,
    schooi_review_result = case
        when #{reviewStatus} in (0, 1) then 0
        when #{reviewStatus} = 2 and schooi_review_result is null then 2
        else schooi_review_result
    end,
    school_reviewed_at = case
        when #{reviewStatus} in (0, 1) then now()
        else school_reviewed_at
    end,
    school_review_reason = case
        when #{reviewStatus} in (0, 1) then '因院级状态变更自动驳回'
        else school_review_reason
    end,
    school_audit_by = case
        when #{reviewStatus} in (0, 1) then 'system'
        else school_audit_by
    end,
    update_time = now()
where achievement_id in

    #{achievementId}

update sam_achievement
set schooi_review_result = #{reviewStatus},
    school_reviewed_at = case
        when #{reviewStatus} = 2 then null
        else now()
    end,
    school_review_reason = case
        when #{reviewStatus} = 0 then #{rejectReason}
        else null
    end,
    school_audit_by = case
        when #{reviewStatus} = 2 then null
        else #{auditBy}
    end,
    update_time = now()
where achievement_id in

    #{achievementId}

and review_result = 2

